using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

// --- ML.NET setup ---
var mlContext = new MLContext(seed: 42);

var csvPath = Path.Combine(app.Environment.ContentRootPath, "Data", "customers.csv");

// Load CSV with Churned as string, then map Yes/No -> bool Label
var rawData = mlContext.Data.LoadFromTextFile<RawCustomerData>(csvPath, hasHeader: true, separatorChar: ',');

var labelMapping = mlContext.Transforms.Conversion.MapValue(
    "Label",
    new Dictionary<string, bool> { ["Yes"] = true, ["No"] = false },
    inputColumnName: "ChurnedRaw");

var mappedData = labelMapping.Fit(rawData).Transform(rawData);

// Build training pipeline
var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.FastTree(
        labelColumnName: "Label",
        featureColumnName: "Features",
        numberOfLeaves: 4,
        numberOfTrees: 10,
        minimumExampleCountPerLeaf: 1));

var model = pipeline.Fit(mappedData);

// Evaluate
var predictions = model.Transform(mappedData);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

var predictionEngine = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

// --- Endpoints ---
app.MapGet("/", () => Results.Json(new
{
    accuracy = Math.Round(metrics.Accuracy, 4),
    auc = Math.Round(metrics.AreaUnderRocCurve, 4),
    f1Score = Math.Round(metrics.F1Score, 4)
}));

app.MapPost("/predict", (PredictRequest request) =>
{
    var input = new CustomerData
    {
        Age = request.Age,
        Income = request.Income,
        Region = request.Region ?? "East",
        PurchaseHistory = request.PurchaseHistory
    };

    var prediction = predictionEngine.Predict(input);

    return Results.Json(new
    {
        willChurn = prediction.PredictedLabel,
        probability = Math.Round(prediction.Probability, 4)
    });
});

app.Run();

// --- Data classes ---

public class RawCustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = string.Empty;
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4), ColumnName("ChurnedRaw")] public string ChurnedRaw { get; set; } = string.Empty;
}

public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = string.Empty;
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [ColumnName("Label")] public bool Label { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")] public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}

public class PredictRequest
{
    public float Age { get; set; }
    public float Income { get; set; }
    public string? Region { get; set; }
    public float PurchaseHistory { get; set; }
}

